class BusinessModelEngine:
    def analyze(self,text:str,domain:str='general',keywords:Optional[List[str]]=None,market_gap:Optional[Dict[str,Any]]=None,trend_trajectory:Optional[Dict[str,Any]]=None,market_formation:Optional[Dict[str,Any]]=None,moat:Optional[Dict[str,Any]]=None,risk_regulation:Optional[Dict[str,Any]]=None,connector_sources:Optional[Dict[str,Any]]=None)->Dict[str,Any]:
        s=self._signals(text or '',keywords or [],domain,market_gap or {},trend_trajectory or {},market_formation or {},moat or {},risk_regulation or {},connector_sources or {})
