    def _revenue(self,s):
        sec=s['sector']
        if sec=='climate_insurance': ranked=[('enterprise_subscription',0.46+s['buyer_pull_score']*.16+s['market_gap_confidence']*.10,'Best fit for insurers, reinsurers, and brokers using recurring climate-risk intelligence.'),('risk_data_product_subscription',0.42+s['category_creation_score']*.16+s['moat_score']*.12,'Climate exposure benchmarks and repricing signals can become premium data products.'),('underwriting_module_license',0.38+s['sector_specific_term_count']*.025+s['buyer_pull_score']*.10,'Underwriting teams can adopt targeted repricing and exposure modules.')]
