    def _sector_count(self,sector,c):
        pats={'climate_insurance':[r'insurance',r'reinsurance',r'underwriting',r'catastrophe',r'weather losses',r'exposure',r'repricing'], 'financial_market_intelligence':[r'credit',r'liquidity',r'portfolio',r'institutional'], 'industrial_supply_chain':[r'supplier',r'shortage',r'bottleneck',r'procurement',r'erp'], 'energy_infrastructure':[r'grid',r'utility',r'transmission'], 'healthcare_operations':[r'hospital',r'patient',r'capacity'], 'defense_autonomy':[r'defense',r'mission',r'drone']}.get(sector,[])
