    def _b(self,v): return max(0,min(.96,v))
    def _level(self,score): return {'level':'strong' if score>=.72 else 'moderate' if score>=.52 else 'early','score':round(score,4)}
    def _burden(self,score): return {'level':'high' if score>=.65 else 'moderate' if score>=.42 else 'low','score':round(score,4)}
