    def _get(self,obj,*path):
        cur=obj
        for k in path:
            if not isinstance(cur,dict): return 0.0
            cur=cur.get(k,0.0)
        try:return float(cur or 0.0)
        except Exception:return 0.0
    def _text(self,obj,*path):
        cur=obj
        for k in path:
            if not isinstance(cur,dict): return ''
            cur=cur.get(k,'')
        return str(cur or '')
